// node_conv_238 -- pointwise 1x1 conv2d on tiled-streaming contract.
// IC=512, OC=128, IH=IW=OH=OW=28, stride=1, MP=4, channel_tile=32.
// IN_BEATS=16, OUT_BEATS=4, OC_PASSES=32. Per-pass cycles = MP*K_TOTAL+6 = 2054.
// First valid_out = IN_BEATS + OC_PASSES*(MP*K_TOTAL+6) = 16 + 32*2054 = 65744.
module node_conv_238 (
    input  wire              clk,
    input  wire              rst_n,
    input  wire              valid_in,
    output reg               ready_in,
    input  wire [255:0]      data_in,
    output reg               valid_out,
    output reg  [255:0]      data_out
);
    localparam integer IC           = 512;
    localparam integer OC           = 128;
    localparam integer OH           = 28;
    localparam integer OW           = 28;
    localparam integer KH           = 1;
    localparam integer KW           = 1;
    localparam integer K_TOTAL      = IC * KH * KW;
    localparam integer MP           = 4;
    localparam integer OC_PASSES    = (OC + MP - 1) / MP;
    localparam integer CHANNEL_TILE = 32;
    localparam integer IN_BEATS     = (IC + CHANNEL_TILE - 1) / CHANNEL_TILE;
    localparam integer OUT_BEATS    = (OC + CHANNEL_TILE - 1) / CHANNEL_TILE;
    localparam integer TILE_BITS    = CHANNEL_TILE * 8;
    localparam integer NUM_PIXELS   = OH * OW;

    localparam integer SCALE_MULT   = 16759;
    localparam integer SCALE_SHIFT  = 21;

    localparam integer PROD_W        = 16;
    localparam integer ACC_W         = PROD_W + 12;
    localparam integer BIAS_W        = 32;
    localparam integer BIASED_W      = ((ACC_W > BIAS_W) ? ACC_W : BIAS_W) + 1;
    localparam integer SCALE_MAG_W   = 15;
    localparam integer SCALE_CONST_W = SCALE_MAG_W + 1;
    localparam integer SCALED_W      = BIASED_W + SCALE_CONST_W;

    localparam signed [SCALE_CONST_W-1:0] SCALE_MULT_CONST = SCALE_MULT;
    localparam signed [SCALED_W-1:0] SCALE_ROUND_HALF =
        {{(SCALED_W-1){1'b0}}, 1'b1} <<< (SCALE_SHIFT - 1);
    localparam signed [SCALED_W-1:0] SCALE_ROUND_HALF_M1 =
        SCALE_ROUND_HALF - {{(SCALED_W-1){1'b0}}, 1'b1};

    localparam [2:0] ST_LOAD    = 3'd0;
    localparam [2:0] ST_RUNNING = 3'd1;
    localparam [2:0] ST_DRAIN   = 3'd2;
    localparam [2:0] ST_BIAS    = 3'd3;
    localparam [2:0] ST_SCALE   = 3'd4;
    localparam [2:0] ST_OUTPUT  = 3'd5;
    localparam [2:0] ST_EMIT    = 3'd6;

    (* rom_style = "block", ram_style = "block" *)
    reg signed [7:0]  weights [0:OC*K_TOTAL-1];
    (* rom_style = "block", ram_style = "block" *)
    reg signed [31:0] biases  [0:OC-1];

    initial begin
        $readmemh("C:/Users/User/Desktop/RTL_LLM_CLAUDE/nn2rtl-repo/output/weights/node_conv_238_weights.hex", weights);
        $readmemh("C:/Users/User/Desktop/RTL_LLM_CLAUDE/nn2rtl-repo/output/weights/node_conv_238_bias.hex", biases);
    end

    reg [2:0]  state;
    reg [4:0]  pixel_row;
    reg [4:0]  pixel_col;
    reg [9:0]  active_emit_count;
    reg [4:0]  in_beat_idx;
    reg [3:0]  out_beat_idx;
    reg [5:0]  oc_group;
    reg [1:0]  lane_counter;
    reg [9:0]  k_counter;
    reg [1:0]  drain_count;

    reg [IC*8-1:0]      in_latch_flat;
    reg [OC*8-1:0]      out_pack;

    reg signed [7:0]    weight_q;
    reg signed [7:0]    in_q;
    reg                 mac_valid_q1;
    reg [1:0]           mac_lane_q1;
    (* use_dsp = "yes" *)
    reg signed [PROD_W-1:0] mul_q;
    reg                 mac_valid_q2;
    reg [1:0]           mac_lane_q2;

    reg signed [ACC_W-1:0]    acc    [0:MP-1];
    reg signed [BIASED_W-1:0] biased [0:MP-1];
    reg signed [SCALED_W-1:0] scaled [0:MP-1];
    reg signed [SCALED_W-1:0] v_tmp;

    integer i;
    integer lane;
    integer global_oc;

    wire [19:0] weight_addr;
    assign weight_addr = (oc_group * MP + lane_counter) * K_TOTAL + k_counter;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state             <= ST_LOAD;
            ready_in          <= 1'b1;
            valid_out         <= 1'b0;
            data_out          <= 256'b0;
            pixel_row         <= 0;
            pixel_col         <= 0;
            active_emit_count <= 0;
            in_beat_idx       <= 0;
            out_beat_idx      <= 0;
            oc_group          <= 0;
            lane_counter      <= 0;
            k_counter         <= 0;
            drain_count       <= 0;
        end else begin
            case (state)
                ST_LOAD: begin
                    valid_out <= 1'b0;
                    ready_in  <= 1'b1;
                    if (valid_in) begin
                        if (in_beat_idx == IN_BEATS - 1) begin
                            in_beat_idx  <= 0;
                            ready_in     <= 1'b0;
                            oc_group     <= 0;
                            lane_counter <= 0;
                            k_counter    <= 0;
                            drain_count  <= 0;
                            state        <= ST_RUNNING;
                        end else begin
                            in_beat_idx <= in_beat_idx + 1;
                        end
                    end
                end
                ST_RUNNING: begin
                    if (k_counter == K_TOTAL - 1) begin
                        k_counter <= 0;
                        if (lane_counter == MP - 1) begin
                            lane_counter <= 0;
                            drain_count  <= 0;
                            state        <= ST_DRAIN;
                        end else begin
                            lane_counter <= lane_counter + 1;
                        end
                    end else begin
                        k_counter <= k_counter + 1;
                    end
                end
                ST_DRAIN: begin
                    if (drain_count == 2'd2) state <= ST_BIAS;
                    else drain_count <= drain_count + 1;
                end
                ST_BIAS:  state <= ST_SCALE;
                ST_SCALE: state <= ST_OUTPUT;
                ST_OUTPUT: begin
                    if (oc_group == OC_PASSES - 1) begin
                        valid_out    <= 1'b1;
                        data_out     <= out_pack[0 +: TILE_BITS];
                        out_beat_idx <= 1;
                        state        <= ST_EMIT;
                    end else begin
                        oc_group     <= oc_group + 1;
                        lane_counter <= 0;
                        k_counter    <= 0;
                        drain_count  <= 0;
                        state        <= ST_RUNNING;
                    end
                end
                ST_EMIT: begin
                    if (out_beat_idx == OUT_BEATS) begin
                        valid_out    <= 1'b0;
                        ready_in     <= 1'b1;
                        out_beat_idx <= 0;
                        oc_group     <= 0;
                        state        <= ST_LOAD;
                        if (active_emit_count == NUM_PIXELS - 1) begin
                            active_emit_count <= 0;
                            pixel_row <= 0; pixel_col <= 0;
                        end else begin
                            active_emit_count <= active_emit_count + 1;
                            if (pixel_col == OW - 1) begin
                                pixel_col <= 0; pixel_row <= pixel_row + 1;
                            end else pixel_col <= pixel_col + 1;
                        end
                    end else begin
                        data_out     <= out_pack[out_beat_idx * TILE_BITS +: TILE_BITS];
                        out_beat_idx <= out_beat_idx + 1;
                    end
                end
                default: state <= ST_LOAD;
            endcase
        end
    end

    always @(posedge clk) begin
        mac_valid_q1 <= 1'b0;
        mac_valid_q2 <= mac_valid_q1;
        mac_lane_q2  <= mac_lane_q1;
        mul_q        <= weight_q * in_q;
        if (mac_valid_q2) acc[mac_lane_q2] <= acc[mac_lane_q2] + mul_q;
        case (state)
            ST_LOAD: if (valid_in) begin
                in_latch_flat[in_beat_idx * TILE_BITS +: TILE_BITS] <= data_in;
                if (in_beat_idx == IN_BEATS - 1)
                    for (i = 0; i < MP; i = i + 1) acc[i] <= 0;
            end
            ST_RUNNING: begin
                weight_q     <= weights[weight_addr];
                in_q         <= $signed(in_latch_flat[k_counter * 8 +: 8]);
                mac_valid_q1 <= 1'b1;
                mac_lane_q1  <= lane_counter;
            end
            ST_BIAS: for (lane = 0; lane < MP; lane = lane + 1)
                biased[lane] <= $signed(acc[lane]) + $signed(biases[oc_group * MP + lane]);
            ST_SCALE: for (lane = 0; lane < MP; lane = lane + 1)
                scaled[lane] <= $signed(biased[lane]) * $signed(SCALE_MULT_CONST);
            ST_OUTPUT: begin
                for (lane = 0; lane < MP; lane = lane + 1) begin
                    v_tmp = (scaled[lane] + (scaled[lane][SCALED_W-1] ? SCALE_ROUND_HALF_M1 : SCALE_ROUND_HALF)) >>> SCALE_SHIFT;
                    global_oc = oc_group * MP + lane;
                    out_pack[global_oc*8 +: 8] <= (v_tmp > 127) ? 8'sd127 : (v_tmp < -128) ? -8'sd128 : v_tmp[7:0];
                end
                if (oc_group != OC_PASSES - 1)
                    for (i = 0; i < MP; i = i + 1) acc[i] <= 0;
            end
            default: ;
        endcase
    end
endmodule
